custom_css:
/*
《 𝐒𝐀𝐓𝐈𝐒 - Custom 》
作者: 睏暝@woolenbrave
版本：v2.7
此美化免費發布於旅程、尾巴鎮DC，請勿商用與二傳，二改請保留代碼作者標註。
*/

/*💠字體💠*/
@import url("https://fontsapi.zeoseven.com/79/main/result.css");
@import url("https://fontsapi.zeoseven.com/285/main/result.css");

/*💠全局💠*/
:root {
    /*文字*/
    --mainfont: "Clear Han Serif"; /*正文字體*/
    --secfont: "Noto Serif CJK";/*裝飾字體*/
    --text-size: 1em; /*正文字體大小*/
    --text-padding: 10px; /*正文與聊天框邊界的距離*/
    --line-height: 1.5em; /*行高*/
    --line-space: 1.3em; /*段距*/
    --indent: 2em; /*首行縮排*/

    /*主題元素顏色*/
    --itemcolor: var(--SmartThemeUnderlineColor);
    --itemcolor-sec: #937A6B;

    /*思維鏈文案*/
    --CotText: "「 我的心是曠野之鳥。」";

    --panel-color: var(--SmartThemeChatTintColor);/*左右欄*/
    --panel-color-phone: var(--SmartThemeBlurTintColor);/*手機左右欄*/

    --SmartThemeRadius: 4px;/*全局圓角*/
    --scrollbar: 5px; /*滾動條寬度*/
    --chatborder: 1px solid  var(--itemcolor20);/*聊天氣泡外框*/
}

/*💠頂欄&底欄💠*/
:root {
    --TopBarIconColor: var(--SmartThemeBodyColor);/*圖標顏色*/
    --TopBarIconOpacity: 0.25;/*透明度*/
    --TopBarIconSize: 18px;/*頂欄圖標大小*/
    --BottomBarIconSize: 20px;/*底欄圖標大小*/ 
    --TopbarColor: var(--SmartThemeChatTintColor); /*頂底欄背景顏色*/
    --IconPhone: 30px;/*手機端頂欄圖標下移，改成0恢復原狀🥕*/
}

/*頂欄圖標替換(拿掉標註使用)*/
/*#top-settings-holder .drawer-icon::before {
    content: "";
    background-image: url('');
}
#top-settings-holder > .drawer:nth-child(even) .drawer-icon::before {
    content: "";
    background-image: url('');
}*/

/*底欄圖標*/
/*#options_button::before {
  content: "";
  background-image: url('');
}
#extensionsMenuButton::before {
    content: "";
    background-image: url('');
}
#send_but::before {
  content: "";
  background-image: url('');
}*/

/*🪲顏色*/
:root {
    --itemcolor80: color-mix(in srgb, var(--itemcolor) 80%, transparent);
    --itemcolor60: color-mix(in srgb, var(--itemcolor) 60%, transparent);
    --itemcolor45: color-mix(in srgb, var(--itemcolor) 45%, transparent);
    --itemcolor30: color-mix(in srgb, var(--itemcolor) 30%, transparent);
    --itemcolor20: color-mix(in srgb, var(--itemcolor) 20%, transparent);
    --itemcolor08: color-mix(in srgb, var(--itemcolor) 8%, transparent);
    --itemcolor-sec08: color-mix(in srgb, var(--itemcolor-sec) 08%, transparent);
    --itemcolor-sec20: color-mix(in srgb, var(--itemcolor-sec) 20%, transparent);
    --itemcolor-sec45: color-mix(in srgb, var(--itemcolor-sec) 45%, transparent);
    --itemcolor-sec80: color-mix(in srgb, var(--itemcolor-sec) 60%, transparent);
}

/*🪲頭像 */
/*聊天框內的頭像*/
.mes .avatar {
    top: -135px; /*頭像高度位置😡*/
    z-index: 20; left: 50%; position: relative !important;
}

.mes .avatar img {
    height: 80px;/*頭像長*/
    width: 80px;/*寬*/
    object-position: center 50%; /*頭像圖片位置*/
    border: 1px solid var(--SmartThemeBlurTintColor);
    object-fit: cover !important; transform: translateX(-50%); z-index: 10 !important; transition: transform 0.6s ease-out, box-shadow 0.6s ease-out !important; position: absolute;
}

body.square-avatars .avatar,
body.square-avatars .avatar img {
    border-radius: var(--SmartThemeRadius) !important;
}
#chat .mes .avatar img {
    top: -10px;
}
.avatar img {
    box-shadow: 0 0 6px rgba(0,0,0,0.4); border: 1px solid var(--itemcolor80);
}

.mesAvatarWrapper {
    position: static !important;
    margin: 0 auto;
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
}

.mes .avatar::before {
    transition: transform 0.6s ease-out, box-shadow 0.6s ease-out;
}

.mes .avatar:hover::before,
.mes .avatar:hover img,
.mes .avatar img:hover {
    transform: translateX(-50%) translateY(-8px) !important;
    box-shadow: 0 10px 16px rgba(0, 0, 0, 0.4) !important;
}

/*🪲正文與聊天氣泡*/
/*對白樣式
.mes_text q {
  margin: 0 6px 0 0px;
  border-bottom: 1px dotted color-mix(in srgb, var(--SmartThemeQuoteColor) 100%, transparent) !important;
}

/* 聊天氣泡邊距 */
#chat { padding: 8px 0px 8px var(--scrollbar);}

/* 手機端聊天框 隱藏滾動條+對齊 */
@media screen and (max-width: 768px) {
    #chat::-webkit-scrollbar { display: none !important;}
    #chat { padding: 8px 5px !important; }}

.mes {
  margin-top: 4px;
  flex-direction: column;
  align-items: center;
  border-radius: var(--SmartThemeRadius) !important;
  padding-top: 200px !important; /*😡*/
  border: var(--chatborder) !important;
}

.mes_block {
  width: 100%;
  padding: 0 0 55px 0;
}

.mes_text {
  font-size: var(--text-size);
  font-family: var(--mainfont);
  text-align: justify;
  width: 100% !important;
  line-height: var(--line-height);
  letter-spacing: 1px;
  padding: 25px var(--text-padding) 0px var(--text-padding) !important;
  z-index: 20 !important;

}

.mes_text p {
    margin-bottom: var(--line-space) !important;
    text-indent: var(--indent);
}

.mes_text p:last-child {
    margin-bottom: 0px !important;
}

/*引用塊*/
.mes_text blockquote {
  background: transparent;
  padding: 20px 20px;    
  border-radius: 10px;
  margin-bottom: 20px;
  border-left: 3px double var(--itemcolor80);
  border-right: 3px double var(--itemcolor80);
  box-shadow: inset 0 0 10px var(--itemcolor30);
  transition: border 0.6s ease, box-shadow 0.6s ease-out;
}

.mes_text blockquote:hover {
  border-left: 3px double var(--itemcolor);
  border-right: 3px double var(--itemcolor);
  box-shadow: inset 0 0 15px var(--itemcolor60) !important;
}

/*代碼包裹 by @Junezz 復古MacOs*/
  code {
    background-color: transparent;
    color: var(--SmartThemeBodyColor) !important;
    border: 1px solid var(--itemcolor30);
    box-shadow: inset 0 0 5px var(--itemcolor30) !important;
    font-size: calc(var(--mainFontSize)* 0.98);
    padding: 0px 3px;
    line-height: var(--line-height) !important;
}
/*對齊*/
.last_mes .mesAvatarWrapper {
  padding-bottom: 0px;
}
.mes_block .ch_name {
  min-height: 0 !important;
  height: 0 !important;
}
/*選取文本樣式 by@potato_juice9*/
.mes_text ::selection {
    background: var(--itemcolor) !important;
    color: var(--SmartThemeBlurTintColor);
}

/*🪲切換消息*/
.swipeRightBlock {  
  right: calc(var(--text-padding)) !important;
  bottom: 8px;
}
.swipe_left {
  bottom: 22px;
}
.swipe_left, .swipe_right {
  font-size: 15px;
}

/*🪲聊天氣泡頂部元素*/

.mes_buttons, .mes_edit_buttons, .mes_ghost, .mes .name_text, .mesIDDisplay, .mes_timer,
.tokenCounterDisplay,.icon-svg,.timestamp {
  position: absolute !important;
  z-index: 20  !important;
}

/*🍺角色名字*/
.mes .name_text {
  top: 156px;/*😡*/
  left: 50%;
  transform: translateX(-50%);
  font-size: 16px;
  font-family: var(--secfont);
  opacity: 1;
  color: var(--SmartThemeBodyColor) !important;
}
.mes .name_text::before {
  content: "-";
  margin-right: 8px;
  display: inline-block;
  transform: scaleX(-1) translateY(-1.5px);
  opacity: 0.7;
}
.mes .name_text::after {
  content: "-";
  margin-left: 8px;
  display: inline-block;
  transform: translateY(-1.5px);
  opacity: 0.7;
}

/*🍺日期*/
.timestamp {
    top: 182px; /*😡*/
    font-size: 11px;
    letter-spacing: 2px;
    transform: translateX(-50%);
    left: 50%;
    opacity: 1 !important;
    transition: opacity 0.6s ease, box-shadow 0.6s ease-out;
    font-family: var(--secfont);
    color: var(--SmartThemeBodyColor) !important;
}

.mes_ghost:hover, .mes .name_text:hover, .timestamp:hover {
  text-shadow: 0 0 16px var(--SmartThemeBodyColor) !important;
}

.mes_reasoning_actions,
.mes_ghost,
#chat .mes_buttons .mes_button,
#chat .mes_edit_buttons .menu_button,
#chat .favorite-toggle-icon {
    color: color-mix(in srgb, var(--SmartThemeBodyColor) 60%, transparent);
    transition: color 0.6s ease;
    filter:  none;
}
#chat .mes_buttons .mes_button:hover,
#chat .mes_edit_buttons .menu_button:hover,
#chat .mes_reasoning_actions .edit_button:hover,
#chat .favorite-toggle-icon:hover {
    color: color-mix(in srgb, var(--SmartThemeBodyColor) 80%, transparent);
}

/*🍺小鉛筆*/
.mes_buttons {
  top: 15px !important;
  right: var(--text-padding);
  padding: 5px;
}

.mes_edit::before { 
  content: "\f56b";
  font-family: "Font Awesome 6 Free" !important;
  font-weight: 900;
}

.extraMesButtonsHint {
  padding-right: 8px;
}

/*🍺正文edit按键*/
.mes_edit_buttons {
    top: 12px;
    padding: 0;
    filter: none;
    right: 14px;
}
#chat .mes_edit_buttons .menu_button {
    color: color-mix(in srgb, var(--SmartThemeBodyColor) 60%, transparent);
    box-shadow: inset 0 0 5px var(--itemcolor45) !important;
    transition: opacity 0.6s ease;
    filter:  none;
}

/*🍺幽靈圖標*/
.mes_ghost {
    top: 55px; 
    right: calc(var(--text-padding) + 6px);
    transition: opacity 0.6s ease;
}

/*🍺三元素*/
.mes_timer, .mesIDDisplay, .tokenCounterDisplay {
    padding: 1px 10px 2px 10px;
    opacity: 1 !important;
    transition: border 0.6s ease, opacity 0.6s ease, transform 0.6s ease, box-shadow 0.6s ease-out;
    font-family: var(--secfont);
    border: 1px solid transparent;
    color: color-mix(in srgb, var(--SmartThemeBodyColor) 80%, transparent) !important;
}
.mes_timer:hover, .tokenCounterDisplay:hover, .mesIDDisplay:hover {
  opacity: 1 !important;
  border: 1px solid var(--itemcolor80);
  box-shadow: inset 0 0 5px var(--itemcolor80) !important;
  transform: translateX(8px);
}

/*🍺訊息編號*/
.mesIDDisplay {
  top: 15px;
  font-size: 17px !important;
}

/*🍺Token*/
.tokenCounterDisplay { 
  top: 50px;
  font-size: 12px !important;
}

/*🍺計時*/
.mes_timer {
  top: 78px ;
  font-size: 12px !important;
}

.mes_timer, .mesIDDisplay, .tokenCounterDisplay {
    left: var(--text-padding);
}

.mesIDDisplay::before {
  content: "Ch";
  margin-right: 5px;
  font-size: 15.5px !important;
}
.tokenCounterDisplay::before {
  content: "Tokens";
  margin-right: 5px;
  font-size: 9.5px !important;
}
.mes_timer::before {
  content: "Time";
  margin-right: 5px;
  font-size: 9.5px !important;
}

/*頂欄底欄圖標*/
#send_but,
#extensionsMenuButton,
#options_button,
#top-settings-holder .drawer-icon {
    background-repeat: no-repeat; background-position: center; display: inline-block;
    font-family: "Font Awesome 6 Free" !important; font-weight: 900;
    background-size: var(--TopBarIconSize);
    width: 20px;
    height: 20px;
}
:is(#quick-reply-rocket-button, #options_button, #extensionsMenuButton, #send_but, #top-settings-holder .drawer-icon) {
    transition: opacity 0.2s ease-in-out, filter 0.2s ease-in-out !important;
    &:hover {
        opacity: calc(var(--TopBarIconOpacity) + 0.5) !important;
  }
}

/*🪲頂欄*/
body.no-blur #top-bar, #top-bar {
    background-color: var(--TopbarColor) !important;
    border-radius: 0;
}
#top-bar .drawer-icon, 
.drawer-toggle .drawer-icon {
    font-size: var(--TopBarIconSize) !important;
    color: var(--TopBarIconColor) !important; 
    opacity: var(--TopBarIconOpacity);
}
body.no-blur #top-bar {
  padding-bottom: 0px !important;
}

/*🪲底欄*/
body.no-blur #send_form, #send_form {
    background-color: var(--TopbarColor) !important;
    border: none !important;
    outline: none !important;
    border-radius: 0 !important;
    border-top: var(--TopbarBorder) !important;
    padding: 1px 8px 2px 8px;
}
#rightSendForm>div, #leftSendForm>div {
    font-size: var(--BottomBarIconSize) !important;
    color: var(--TopBarIconColor) !important;
    opacity: var(--TopBarIconOpacity) !important;
}
#send_textarea::placeholder {
  color: transparent;
  opacity: 0;
}

/*消除底欄縫隙 by@_nak.a.ri*/
#form_sheld {
  margin: 0 auto !important;
}
/*修正版by咩野*/
body:not(.waifuMode) #sheld {
  top: var(--bottomFormBlockSize);
  height: calc(100dvh - var(--bottomFormBlockSize));
  min-height: calc(100dvh - var(--bottomFormBlockSize));
}

/*🪲左右欄*/
#right-nav-panel, #left-nav-panel {
    background-color: var(--panel-color) !important;
    border: none;
}
#left-nav-panel { box-shadow: 1px 0px 0 var(--panel-color) !important; }
#right-nav-panel { box-shadow: -1px 0px 0 var(--panel-color) !important; }

/* 手機端左右欄背景顏色 */
@media screen and (max-width: 768px) {
  #left-nav-panel, #right-nav-panel { background-color: var(--panel-color-phone) !important; }
}
/* PC端左右欄佔滿全屏 */
@media screen and (min-width: 1025px) and (pointer: fine) {
  #left-nav-panel, #right-nav-panel { top: 0 !important; height: 100vh !important; max-height: 100vh !important; }
}
/*🪲右欄角色管理*/
.bogus_folder_select:hover, .character_select:hover {
    background-color: transparent !important; 
    box-shadow: inset 0 0 8px var(--itemcolor);
    border-radius: var(--SmartThemeRadius);
}
.bogus_folder_select, .character_select {padding: 8px;}

#rm_button_characters, #rm_button_panel_pin_div, #lm_button_panel_pin_div, #WI_button_panel_pin_div {
    font-size: 1.15em !important;
    opacity:  1;
    padding-bottom: 5px;
}

/*角色收藏*/
.hotswap.avatars_inline { display: flex; flex-wrap: wrap; transition: all 1s ease; scrollbar-width: none; }
.hotswap.avatars_inline::-webkit-scrollbar { display: none; }
.hotswap.avatars_inline:hover { max-height: 300px; overflow: auto; }

/*收藏角色頭像框 by @rech0_viixi 雙色盒子*/
.character_select.is_fav .avatar {
  outline: 4px double var(--itemcolor);
}
.character_select.is_fav .ch_name {
  color: var(--itemcolor);
}

/*使用者角色選中頭像 by @mayonnaise58*/
.avatar-container.interactable.selected {
    background-color: var(--itemcolor08); 
    box-shadow: inset 0 0 8px var(--itemcolor80);
    border-radius: var(--SmartThemeRadius) !important;
    border: none;
}
.avatar-container.interactable:hover {
    border-radius: calc(var(--SmartThemeRadius) + 2px);
    background-color: transparent !important;
    box-shadow: inset 0 0 8px var(--itemcolor80);
}
/*角色管理按鈕*/
#charListFixedTop .rm_tag_filter .tag {
    background: transparent !important;
    color: var(--itemcolor);
    filter: none;
    border: 0;
    box-shadow: inset 0 0 8px var(--itemcolor60) !important;
}

/*🪲擴充頁面標題*/
#aistudio_proxy_button,
#extensions_settings .inline-drawer-toggle.inline-drawer-header, 
#extensions_settings2 .inline-drawer-toggle.inline-drawer-header {
  padding: 6px 11px !important;
  transition: background-color 0.2s ease;
}
#aistudio_proxy_button:hover,
#extensions_settings .inline-drawer-toggle.inline-drawer-header:hover, 
#extensions_settings2 .inline-drawer-toggle.inline-drawer-header:hover {
  background-color: var(--itemcolor-sec20) !important;
  filter: none;
}
/*擴充功能關閉條目*/
.extensions_info .extension_disabled {
  color: var(--SmartThemeBodyColor) !important;
}

/*🪲思維鏈*/
.mes_reasoning_details {
    margin-left: var(--text-padding);
    margin-right: var(--text-padding);
    position: relative !important;
}
/*思維鏈內容主體*/
.mes_reasoning {
    max-height: 480px; /*思維鏈內容開啟高度*/
    overflow-y: auto;
    overflow-x: hidden;
    color: var(--SmartThemeBodyColor) !important;
    margin-bottom: 18px;
    box-shadow: inset 0 0 10px var(--itemcolor-sec20);
    border: 1px dotted var(--itemcolor-sec20);
    background: linear-gradient(
        to bottom,
        var(--itemcolor-sec08) 0%,
        transparent 100%) !important;
    margin-top: 35px;
}
/*隱藏原始箭頭*/
.mes_reasoning_details .mes_reasoning_arrow {
    display: none !important;
}
.mes_reasoning_header_block {
    margin: 0;
}
/*思維鏈編輯框*/
.reasoning_edit_textarea { 
  margin-top: 50px; margin-bottom: 15px; 
}
.mes_reasoning_actions.flex-container {
    position: absolute !important;
    top: 60px !important;
    right: 0; 
    z-index: 30;
}
.mes_reasoning_edit_done,
.mes_reasoning_edit_cancel,
.mes_reasoning_delete {
    margin-top: -55px !important;
    filter: none !important;
}

.mes_reasoning_header {
    font-size: 0 !important;
    text-align: center;
    display: block;
    background: transparent;
    justify-content: center !important;
    width: 100% !important;
    left: -10px;
    height: 40px;
    margin: 15px 0 0 0; 
}
/*🥝思維鏈文案*/
.mes_reasoning_header::after {
    content: var(--CotText);
    display: inline-block;
    font-size: 16px;
    letter-spacing: 3px;
    opacity: 0.8;
    color: var(--itemcolor);
    font-family: var(--secfont);
    font-weight: bold;
}
/*🥝思維鏈動畫*/
.last_mes .mes_reasoning_header::after {
      animation: dreamFloat 8s cubic-bezier(0.42, 0, 0.58, 1) infinite;
      will-change: transform, opacity, filter;
}
@keyframes dreamFloat {
    0% {
        transform: scale(1.01);
        opacity: 0.5;
        filter: blur(0.8px);
    }
    50% {
        transform: scale(0.88);
        opacity: 0.9;
        filter: blur(0px);
        text-shadow: 0 0 15px rgba(var(--itemcolor-rgb), 0.4);
    }
    100% {
        transform: scale(1.01);
        opacity: 0.5;
        filter: blur(0.8px); }
}
.mes_reasoning_header:hover::after {
    opacity: 1 !important;
    filter: blur(0) !important;
    text-shadow: 0 0 5px var(--itemcolor-sec);
}

/*🪲圓角*/
.drawer-content, 
.popup, 
.mes_block, 
.text_pole, 
textarea, 
select,
.inline-drawer-toggle,
.menu_button,
.bg_tab_panel,
input[type='checkbox'] {
    border-radius: var(--SmartThemeRadius) !important;
}

/*🪲去除陰影*/
body .ui-widget-content,
body, #sheld,
.drawer-content, 
.popup, 
#send_form, 
.mes_block, 
.menu_button, 
.text_pole, 
#top-bar, 
.inline-drawer-toggle,
input[type='checkbox'] {
    box-shadow: none !important;
}

/* 🪲標題去陰影 */
#aistudio_proxy_button,
#extensions_settings .inline-drawer-toggle.inline-drawer-header, #extensions_settings2 .inline-drawer-toggle.inline-drawer-header, #user-settings-block h4, .standoutHeader
 {
    background-image: none;
    border-radius: var(--SmartThemeRadius) !important;
    padding: 4px 5px 4px 11px;
    margin-bottom: 5px;
    border: 1px solid var(--itemcolor20);
    background-color: var(--itemcolor-sec08);
}


/*🪲標題 by @rech0_viixi 雙色盒子*/
.standoutHeader strong,
#right-nav-panel h2,
.drawer-content > h3,
.drawer-content
  .flex-container
  h3:first-of-type:not(#Backgrounds .textAlignCenter),
.drawer-content .flex-container .flex-container h3:first-of-type,
.popup h3:not(dialog *) {
  font-size: calc(var(--mainFontSize) * 1.1);
  letter-spacing: 0.1em;
  white-space: nowrap;
  line-height: 2;
  position: relative;
  padding-left: 21px;
  color: var(--SmartThemeBodyColor);
  font-family: "Font Awesome 6 Free" !important;
}
#bg-header-fixed { 
  color: var(--itemcolor80); 
}

/*標題裝飾*/
.standoutHeader strong::before,
#right-nav-panel h2::before,
.drawer-content > h3::before,
.drawer-content
  .flex-container
  h3:first-of-type:not(#Backgrounds .textAlignCenter)::before,
.drawer-content .flex-container .flex-container h3:first-of-type::before,
.popup h3:not(dialog *)::before {
    content: '\f1ce';
    position: absolute;
    left: 0px;
    top: calc(50%);
    transform: translateY(-50%);
    opacity: 0.9;
    font-size: 14px;
    color: var(--itemcolor);
}
/*修正标题没对齐的问题*/
.drawer-content .alignItemsBaseline {
  align-items: center !important;
}

/*🪲抽屜*/
.drawer-content {
    border-radius: 0px !important;
    padding: 12px 12px 5px 12px;
}

/* by @_nak.a.ri */
